parameters.jsCode:
const deal = $('Fetch Deal Context').item.json;
const contacts = $('Fetch Stakeholders').item.json.contacts || [];

// Build stakeholder map
const stakeholders = contacts.map(c => ({
  name: c.name,
  title: c.title,
  email: c.email,
  role: c.role || 'User',
  engagement_level: c.meetings_count > 3 ? 'High' : c.meetings_count > 1 ? 'Medium' : 'Low'
}));

const champion = stakeholders.find(s => s.role === 'Champion' || s.role === 'Decision Maker');
const execSponsor = stakeholders.find(s => s.role === 'Executive Sponsor');

// Build handoff document
const handoff = {
  account_name: deal.account_name,
  account_id: deal.account_id,
  arr: deal.amount,
  plan: deal.plan_name || 'Standard',
  close_date: deal.close_date,
  ae_name: deal.owner_name,
  ae_email: deal.owner_email,
  csm_email: deal.assigned_csm_email,
  csm_name: deal.assigned_csm_name,

  // Deal context
  why_they_bought: deal.pain_points || 'Not documented',
  key_requirements: deal.requirements || [],
  success_criteria: deal.success_criteria || 'Not defined',
  timeline: deal.expected_go_live || 'TBD',
  competitors_evaluated: deal.competitors || [],

  // Stakeholders
  champion: champion ? `${champion.name} (${champion.title})` : 'Not identified',
  exec_sponsor: execSponsor ? `${execSponsor.name} (${execSponsor.title})` : 'Not identified',
  stakeholder_map: stakeholders,

  // Kickoff details
  kickoff_attendees: stakeholders.filter(s => s.engagement_level !== 'Low').map(s => s.email),
  primary_contact_email: champion ? champion.email : (contacts[0] || {}).email
};

return [{ json: handoff }];

